### 场景3：泛型容器适配器

```cpp
// 约束：T 必须是 Container 的成员类型之一
template<typename T, typename Container>
concept ContainerMemberType =
    std::same_as<T, typename Container::value_type> ||
    std::same_as<T, typename Container::size_type> ||
    std::same_as<T, typename Container::iterator> ||
    std::same_as<T, typename Container::const_iterator>;

template<typename T, typename Container>
    requires ContainerMemberType<T, Container>
class TypedView {
    Container& container;
public:
    TypedView(Container& c) : container(c) {}

    // 根据 T 的类型提供不同功能
    auto get() {
        if constexpr (std::same_as<T, typename Container::value_type>) {
            return container.front();
        } else if constexpr (std::same_as<T, typename Container::iterator>) {
            return container.begin();
        }
        // ... 其他情况
    }
};
```

